/* com.erns.coching.log.mapper.UserRecentInfoDAO.load */

SELECT

FROM T_RECENT_INF AA

	AND MEMB_SEQ 	= #{membSeq	, jdbcType=INTEGER}
	AND REF_CODE 	= #{refCode	, jdbcType=VARCHAR}
	AND REF_SEQ1 	= #{refSeq1	, jdbcType=VARCHAR}
	AND REF_SEQ2 = #{refSeq2, jdbcType=INTEGER}
	AND REF_SEQ3 = #{refSeq3, jdbcType=INTEGER}

/* com.erns.coching.log.mapper.UserRecentInfoDAO.getListVo */

SELECT

FROM T_RECENT_INF AA





	OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.log.mapper.UserRecentInfoDAO.getList */
SELECT ZZ.* FROM ( SELECT
, RM.raw_seq , RM.raw_name , RDT.title , RDMI.memb_name AS MANAGER_NAME
FROM T_RECENT_INF AA
JOIN T_RAW_DETAIL RDT ON AA.REF_SEQ1::integer = RDT.raw_detail_seq JOIN T_RAW_MST RM ON RDT.raw_seq = RM.raw_seq JOIN T_MEMB_INF RDMI ON RDT.memb_seq = RDMI.memb_seq
ORDER BY AA.RGT_DTTM DESC
) ZZ
OFFSET #{offset} LIMIT #{rowSize}

/* com.erns.coching.log.mapper.UserRecentInfoDAO.getListCount */
SELECT COUNT(*) FROM T_RECENT_INF AA
JOIN T_RAW_DETAIL RDT ON AA.REF_SEQ1::integer = RDT.raw_detail_seq JOIN T_RAW_MST RM ON RDT.raw_seq = RM.raw_seq JOIN T_MEMB_INF RDMI ON RDT.memb_seq = RDMI.memb_seq

mapper.insert:
    	/* com.erns.coching.log.mapper.UserRecentInfoDAO.insert */

		INSERT INTO T_RECENT_INF (
				MEMB_SEQ
			, REF_CODE
			, REF_SEQ1
			, REF_SEQ2
			, REF_SEQ3
			, RGT_DTTM

		) VALUES (

				#{membSeq		, jdbcType=INTEGER}
			, #{refCode		, jdbcType=VARCHAR}
			, #{refSeq1		, jdbcType=VARCHAR}
			, #{refSeq2		, jdbcType=INTEGER}
			, #{refSeq3		, jdbcType=INTEGER}
			, now()
		) ON CONFLICT (MEMB_SEQ, REF_CODE, REF_SEQ1, REF_SEQ2, REF_SEQ3)
		DO UPDATE SET
    	RGT_DTTM = now()

mapper.delete:
	/* com.erns.coching.log.mapper.UserRecentInfoDAO.delete */

DELETE FROM T_RECENT_INF

	AND MEMB_SEQ 	= #{membSeq	, jdbcType=INTEGER}
	AND REF_CODE 	= #{refCode	, jdbcType=VARCHAR}
	AND REF_SEQ1 	= #{refSeq1	, jdbcType=INTEGER}
	AND REF_SEQ2 = #{refSeq2, jdbcType=INTEGER}
	AND REF_SEQ3 = #{refSeq3, jdbcType=INTEGER}
